#include <array>
#include <iostream>
#include <string_view>

enum Planet
{
    mercury = 0,
    venus,
    earth,
    mars,
    jupiter,
    maxPlanets
};

constexpr std::array<std::string_view, maxPlanets> planetNames{
    "Mercury", "Venus", "Earth", "Mars", "Jupiter"
};

int main()
{
    int input{};
    std::cin >> input;

    if (input >= 0 && input < maxPlanets)
    {
        Planet p{ static_cast<Planet>(input) };
        std::cout << "Planet: " << planetNames[p] << '\n';
    }
    else
    {
        std::cout << "Planet: Unknown" << '\n';
    }

    return 0;
}

