solution_code:
#include <array>
#include <iostream>
#include <string_view>

enum Subject
{
    math = 0,
    science,
    english,
    history,
    maxSubjects
};

constexpr std::array<std::string_view, maxSubjects> subjectNames{
    "Math", "Science", "English", "History"
};

constexpr std::array<int, maxSubjects> passThresholds{
    50, 55, 45, 50
};

int main()
{
    std::array<int, maxSubjects> scores{};

    for (int i{ 0 }; i < maxSubjects; ++i)
        std::cin >> scores[i];

    int passCount{ 0 };

    for (int i{ 0 }; i < maxSubjects; ++i)
    {
        Subject subj{ static_cast<Subject>(i) };
        std::cout << subjectNames[subj] << ": " << scores[subj];

        if (scores[subj] >= passThresholds[subj])
        {
            std::cout << " - Pass" << '\n';
            ++passCount;
        }
        else
        {
            std::cout << " - Fail" << '\n';
        }
    }

    std::cout << "Passed: " << passCount << "/4" << '\n';

    return 0;
}
